    relatedCaseIds: ["case-npc-2026", "case-sirius-atacama-humanoid", "case-ancient-convergence-matrix", "case-temple-banking-suppression-pattern", "case-biological-thread", "case-area51-s4", "case-die-glocke", "case-philadelphia-experiment", "case-pais-navy-patents", "case-arv-fluxliner-mccandlish", "case-gateway-process", "case-stargate-program", "case-110hz-unified-theory", "case-persinger-god-helmet", "case-bentov-consciousness-mechanics", "case-montauk-project", "case-coral-castle", "case-ancient-sites-piezoelectric", "case-cymatics-frequency", "case-sacred-geometry-pattern", "case-pole-shift-consciousness", "case-younger-dryas", "case-bledsoe-contact", "case-mexico-alien-artifacts", "case-psychokinesis-research-global", "case-blindfolded-perception-training", "case-geipan-database", "case-cometa-report", "case-condign-report", "case-dalnegorsk-height-611", "case-mosul-orb", "case-yemen-hellfire", "case-operation-mainbrace", "case-tesla-electromagnetic-research", "case-em-propulsion-physics", "case-dual-suppression-consciousness", "case-reverse-engineering-hierarchy", "case-network-operational-buga-sphere", "case-schumann-shift", "case-classic-uap-substrate-lens", "case-gothic-cathedrals", "case-alchemical-symbolism", "case-dna-antenna", "case-water-network-layer"],
