    evidenceIds: [],
    relatedCaseIds: ["case-robertson-panel", "case-condon-committee", "case-blue-book-701-unknowns", "case-kenneth-arnold", "case-roswell", "case-suppression-architecture"],
    tags: ["project-sign", "estimate-of-the-situation", "vandenberg", "1948", "interplanetary", "destroyed-evidence", "project-grudge", "blue-book", "hynek", "wright-patterson", "first-suppression"],
